class Låsautomat:
  def __init__(self, lösenord):
    self.lösenord = lösenord
    self.tillstånd = 1  # Starttillstånd S1

  def uppdatera_tillstånd(self, knapp):
    """Uppdaterar tillståndet utifrån det nuverande tillståndet och inmatningen
    Inparameter: knapp (str)"""
    knapp = knapp.upper()
    if self.tillstånd == 1:
      if knapp == self.lösenord[0]:
        self.tillstånd = 2
        print("Tillstånd S2: Första rätta bokstaven har tryckts in.")
      else:
        print("Tillstånd S1: Fel knapp. Väntar på rätt inmatning.")

    elif self.tillstånd == 2:
      if knapp == self.lösenord[1]:
        self.tillstånd = 3
        print("Tillstånd S3: Första två rätta bokstäverna har tryckts in.")
      elif knapp == self.lösenord[0]:
        print("Tillstånd S2: Fel knapp, men det är första bokstaven så går till tillstånd 2.")
        self.tillstånd = 2
      else:
        print("Tillstånd S1: Fel knapp. Återgår till starttillståndet.")
        self.tillstånd = 1

    elif self.tillstånd == 3:
      if knapp == self.lösenord[2]:
        self.tillstånd = 4
        print("Tillstånd S4: Lösenordet har tryckts in - låset öppnas!")
      elif knapp == self.lösenord[0]:
        print("Tillstånd S2: Fel knapp, men det är första bokstaven så går till tillstånd 2.")
        self.tillstånd = 2
      else:
        print("Tillstånd S1: Fel knapp. Återgår till starttillståndet.")
        self.tillstånd = 1

    elif self.tillstånd == 4:
      print("Låset är redan öppet.")

  def är_låset_öppet(self):
    """Kontrollera om låset är öppet
    returvärde: True/False"""
    return self.tillstånd == 4


def main():
    lösen = ['B', 'A', 'D']  # Ändra lösenordet här.
    automat = Låsautomat(lösen)

    print("Tryck på knappar (bokstäver A–I) för att öppna låset med koden")

    while not automat.är_låset_öppet():
        knapp = input("Tryck på en knapp: ").strip()
        if len(knapp) != 1 or not knapp.isalpha() or knapp.upper() not in "ABCDEFGHI":
            print("Ange en giltig bokstav (A–I).")
            continue

        automat.uppdatera_tillstånd(knapp)

    print("Grattis! Låset är öppet.")

main()
